// Skill localization catalog. Originally produced by a one-time migration from the
// former latam-skills.json + latam-skill-desc.json assets; those JSON files, their
// GRF extractors and the migration script have since been removed. Edit this file
// directly going forward (it is the source of truth for skill names/descriptions).
//
// Keyed by the engine's internal skill name (unique). `id` is the in-game skill
// id used for item.json references, the ragassets icon URL and the description
// lookup; note several names can legitimately share one id.

export interface SkillMetaEntry {
  /** in-game skill id — canonical identity (item.json, ragassets icon, description) */
  id?: number;
  /** pt-BR display name */
  label?: string;
  /** pt-BR client skill description, rendered in the skill/buff hover tooltip */
  description?: string;
  /** icon namespace override for the iconUrl pipe; defaults to 'skill' */
  iconType?: 'item' | 'skill';
}

