  "Dragon Training": { id: 2007, label: "Adestrar Dragão", description: "Adestrar Dragão ^777777(Dragon Training)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Perícia em Montaria 1^000000\nTipo: ^777777Passiva^000000\nDescrição:\n^777777Enquanto estiver montado, aumenta o\nmovimento, o peso de carga e o dano\nde [Sopro do Dragão] e [Bafo do Dragão].\nNão haverá penalidade de tamanho ao\nequipar Lanças enquanto monta.^000000\nNível l Dano l Vel.Atq recuperada l Peso\n[Nv 1]: ^777777100%^000000 l ^77777720%^000000 l ^777777+700^000000\n[Nv 2]: ^777777110%^000000 l ^77777715%^000000 l ^777777+900^000000\n[Nv 3]: ^777777120%^000000 l ^77777710%^000000 l ^777777+1.100^000000\n[Nv 4]: ^777777130%^000000 l ^7777775%^000000 l ^777777+1.300^000000\n[Nv 5]: ^777777140%^000000 l ^7777770%^000000 l ^777777+1.500^000000" },
  "Dragonic Aura": { id: 5210, label: "Aura Draconiana", description: "Aura Draconiana ^777777(Dragonic Aura)^000000\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Acumular Poder 10,\nSopro do Dragão 10 e Bafo do Dragão 10^000000\nTipo: ^777777Ofensiva^000000\nCusto de AP: ^FF0000150^000000\nDescrição:\n^777777Causa dano físico à distância no alvo.\nInflige mais dano em oponentes das raças\nHumanoide e Anjo. Após o ataque, entra\nem um estado de Aura por 300 segundos.\nNele, aumenta o dano de Sopro do Dragão,\nBafo do Dragão e Lança das Mil Pontas.\nNv. de base, P.ATQ e POD afetam o dano.^000000\nNível l ATQ l ATQ (Anjo e Humanoide)\n[Nv 1]: ^777777950%^000000 l ^7777771.400%^000000\n[Nv 2]: ^7777771.900%^000000 l ^7777772.800%^000000\n[Nv 3]: ^7777772.850%^000000 l ^7777774.200%^000000\n[Nv 4]: ^7777773.800%^000000 l ^7777775.600%^000000\n[Nv 5]: ^7777774.750%^000000 l ^7777777.000%^000000\n[Nv 6]: ^7777775.700%^000000 l ^7777778.400%^000000\n[Nv 7]: ^7777776.650%^000000 l ^7777779.800%^000000\n[Nv 8]: ^7777777.600%^000000 l ^77777711.200%^000000\n[Nv 9]: ^7777778.550%^000000 l ^77777712.600%^000000\n[Nv 10]: ^7777779.500%^000000 l ^77777714.000%^000000" },
  "Dragonology": { id: 284, label: "Dragonologia", description: "Dragonologia ^777777(Dragonology)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Estudo de Livros 9^000000\nTipo: ^777777Passiva^000000\nDescrição:\n^777777Aumenta a resistência, o dano físico e mágico\ncontra oponentes da raça Dragão.\nTambém fornece um pouco de INT.^000000\nNível l INT l ATQ l ATQM l Resistência\n[Nv 1]: ^777777+1^000000 l ^777777+4%^000000 l ^777777+2%^000000 l ^777777+4%^000000\n[Nv 2]: ^777777+1^000000 l ^777777+8%^000000 l ^777777+4%^000000 l ^777777+8%^000000\n[Nv 3]: ^777777+2^000000 l ^777777+12%^000000 l ^777777+6%^000000 l ^777777+12%^000000\n[Nv 4]: ^777777+2^000000 l ^777777+16%^000000 l ^777777+8%^000000 l ^777777+16%^000000\n[Nv 5]: ^777777+3^000000 l ^777777+20%^000000 l ^777777+10%^000000 l ^777777+20%^000000" },
