  "Knowledge of Sun, Moon and Star": { id: 443, label: "Transmissão Solar, Lunar e Estelar", description: "Transmissão Solar, Lunar e Estelar\nNível máximo: ^77777710^000000\nTipo: ^777777Passiva^000000\nDescrição:\n^777777Ao se conectar no jogo dentro de um mapa\ncom alinhamento solar, lunar ou estelar\naumenta a Capacidade de Carga de itens.\nO efeito é cancelado ao mudar de mapa.^000000\nNível l Peso máximo\n[Nv 1] ^777777+10%^000000\n[Nv 2] ^777777+20%^000000\n[Nv 3] ^777777+30%^000000\n[Nv 4] ^777777+40%^000000\n[Nv 5] ^777777+50%^000000\n[Nv 6] ^777777+60%^000000\n[Nv 7] ^777777+70%^000000\n[Nv 8] ^777777+80%^000000\n[Nv 9] ^777777+90%^000000\n[Nv 10] ^777777+100%^000000" },
  "Kyrie Eleison": { id: 73, label: "Kyrie Eleison", description: "Kyrie Eleison\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Angelus 2^000000\nTipo: ^777777Suporte^000000\nDescrição:\n^777777Cria uma barreira no alvo que bloqueia\num número limitado de ataques físicos ou\num dano equivalente ao HP máx. do alvo.^000000\nNível l Bloqueios l HP equivalente\n[Nv 1]: ^7777775 ataques^000000 l ^77777712%^000000\n[Nv 2]: ^7777776 ataques^000000 l ^77777714%^000000\n[Nv 3]: ^7777776 ataques^000000 l ^77777716%^000000\n[Nv 4]: ^7777777 ataques^000000 l ^77777718%^000000\n[Nv 5]: ^7777777 ataques^000000 l ^77777720%^000000\n[Nv 6]: ^7777778 ataques^000000 l ^77777722%^000000\n[Nv 7]: ^7777778 ataques^000000 l ^77777724%^000000\n[Nv 8]: ^7777779 ataques^000000 l ^77777726%^000000\n[Nv 9]: ^7777779 ataques^000000 l ^77777728%^000000\n[Nv 10]: ^77777710 ataques^000000 l ^77777730%^000000" },
  "Land Protector": { id: 288, label: "Proteger Terreno", description: "Proteger Terreno ^777777(Land Protector)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Vulcão 3, Dilúvio 3, Furacão 3^000000\nTipo: ^777777Suporte^000000\nDescrição:\n^777777Protege a área de certas magias de solo,\nanulando e impedindo o uso de habilidades.^000000\n^000088Consome 1 Gema Amarela e 1 Gema Azul.^000000\nNível l Duração l Área protegida\n[Nv 1]: ^777777120 segundos^000000 l ^7777777x7 células^000000\n[Nv 2]: ^777777165 segundos^000000 l ^7777777x7 células^000000\n[Nv 3]: ^777777210 segundos^000000 l ^7777779x9 células^000000\n[Nv 4]: ^777777255 segundos^000000 l ^7777779x9 células^000000\n[Nv 5]: ^777777300 segundos^000000 l ^77777711x11 células^000000" },
  "Laudaagnus": { id: 2047, label: "Lauda Agnus", description: "Lauda Agnus\nNível máximo: ^7777774^000000\nPré-requisitos: ^777777Graça Divina 1^000000\nTipo: ^777777Suporte^000000\nDescrição:\n^777777Chance de aumentar o HP por 1 min.\ne remover Incêndio, Cegueira, Petrificação,\nCongelamento, Cristalização e Hipotermia.^000000\nNível l Chance l HP máx.\n[Nv 1]: ^77777770%^000000 l ^777777+4%^000000\n[Nv 2]: ^77777780%^000000 l ^777777+6%^000000\n[Nv 3]: ^77777790%^000000 l ^777777+8%^000000\n[Nv 4]: ^777777100%^000000 l ^777777+10%^000000" },
  "Learning Potion": { id: 227, label: "Pesquisa de Poções", description: "Pesquisa de Poções ^777777(Learning Potion)^000000\nNível máximo: ^77777710^000000\nTipo: ^777777Passiva^000000\nDescrição:\n^777777Aumenta as chances de produzir poções e\nmelhora a efetividade de cura das poções.^000000\nNível l Efetividade de cura\n[Nv 1]: ^777777+5%^000000\n[Nv 2]: ^777777+10%^000000\n[Nv 3]: ^777777+15%^000000\n[Nv 4]: ^777777+20%^000000\n[Nv 5]: ^777777+25%^000000\n[Nv 6]: ^777777+30%^000000\n[Nv 7]: ^777777+35%^000000\n[Nv 8]: ^777777+40%^000000\n[Nv 9]: ^777777+45%^000000\n[Nv 10]: ^777777+50%^000000" },
  "Lefthand Mastery": { id: 133, label: "Perícia com Mão Esquerda", description: "Perícia com Mão Esquerda ^777777(Left Mastery)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Perícia com Mão Direita 2^000000\nTipo: ^777777Passiva^000000\nDescrição:\n^777777Ao equipar armas de duas mãos, o usuário\nperde 30% de ATQ na mão esquerda.\nAprender a perícia, recupera o ATQ perdido.\nNão funciona com Katar.^000000\nNível l ATQ recuperado\n[Nv 1]: ^77777740%^000000\n[Nv 2]: ^77777750%^000000\n[Nv 3]: ^77777760%^000000\n[Nv 4]: ^77777770%^000000\n[Nv 5]: ^77777780%^000000" },
