  "Lightning Loader": { id: 282, label: "Encantar com Ventania", description: "Encantar com Ventania ^777777(Lightning Loader)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Relâmpago 1,\nEstudo de Livros 5^000000\nTipo: ^777777Suporte^000000\nDescrição:\n^777777Encanta a Arma com propriedade Vento e\naumenta o dano mágico desse elemento.\nSó pode ser usada em você e no grupo.^000000\n^000088Consome 1 Fragmento Amarelo.^000000\nNível l Duração l Dano mágico\n[Nv 1]: ^77777710 minutos^000000 l ^777777+1%^000000\n[Nv 2]: ^77777715 minutos^000000 l ^777777+2%^000000\n[Nv 3]: ^77777720 minutos^000000 l ^777777+3%^000000\n[Nv 4]: ^77777725 minutos^000000 l ^777777+4%^000000\n[Nv 5]: ^77777730 minutos^000000 l ^777777+5%^000000" },
