  "Meow Meow": { id: 5053, label: "Balaio de Gato", description: "Balaio de Gato ^777777(Meow Meow)^000000\nNível máximo: ^7777775^000000\nTipo: ^777777Suporte^000000 / ^CD3278Selva^000000\nPré-requisitos: ^777777Despertar 5^000000\nDescrição:\n^777777Conjura [Despertar] nos membros do Grupo.\nO efeito tem duração um pouco maior.\nafeta todos os membros na tela do usuário.^000000\nNível l Custo de SP l Duração\n[Nv 1]: ^777777100^000000 l ^7777778 segundos^000000\n[Nv 2]: ^77777790^000000 l ^7777778 segundos^000000\n[Nv 3]: ^77777780^000000 l ^77777710 segundos^000000\n[Nv 4]: ^77777770^000000 l ^77777710 segundos^000000\n[Nv 5]: ^77777760^000000 l ^77777712 segundos^000000" },
  "Moonlight Fantasy": { id: 3027, label: "Ilusão do Luar", description: "Ilusão do Luar ^777777(Moonlight Fantasy)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Luar Sinistro 3^000000\nTipo: ^777777Ativa^000000\nDescrição:\n^008080Funciona apenas em PvP/GdE.^000000\n^777777Aumenta ou reduz o HP e SP do alvo.\nEnquanto estiver ativa, personagens que\nreceberem ataques mágicos refletirão o\ndano em uma área de 5x5 células.^000000\nNível l Duração\n[Nv 1]: ^77777710 segundos^000000\n[Nv 2]: ^77777715 segundos^000000\n[Nv 3]: ^77777720 segundos^000000\n[Nv 4]: ^77777725 segundos^000000\n[Nv 5]: ^77777730 segundos^000000" },
  "Moonlight Serenade": { id: 2352, label: "Serenata ao Luar", description: "Serenata ao Luar ^777777(Moonlight Serenade)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Melodia de Morfeu 1^000000\nTipo: ^777777Suporte^000000\nDescrição:\n^008080Apenas Chicotes.^000000\n^777777Aumenta o ATQM.\nDura 180 segundos e afeta membros do\ngrupo em 31x31 células ao redor da usuária.\nO bônus é afetado por [Domínio Musical].^000000\nNível l ATQM\n[Nv 1]: ^777777+7^000000\n[Nv 2]: ^777777+10^000000\n[Nv 3]: ^777777+13^000000\n[Nv 4]: ^777777+15^000000\n[Nv 5]: ^777777+20^000000" },
