  "Mystic Symphony": { id: 5351, label: "Sinfonia Mística", description: "Sinfonia Mística ^777777(Mystic Symphony)^000000\nNível máximo: ^7777771^000000\nPré-requisito: ^777777Atirar Rosas 5,\n    Fúria Estridente 1^000000\nTipo: ^777777Suporte^000000\nCusto de AP: ^FF0000125^000000\nDescrição:\n^008080Apenas com Arco, Chicote ou Instrumento.^000000\n^777777Por 150 segundos, aumenta o dano físico e\nmágico contra as raças Peixe e Humanoide.\nTambém aumenta em 100% o dano de:\nArranjo Musical\nDisparo Rítmico\nAtirar Rosas^000000" },
  "Neutral Barrier": { id: 2273, label: "Campo Protetor", description: "Campo Protetor ^777777(Neutral Barrier)^000000\nNível máximo: ^7777773^000000\nPré-requisitos: ^777777Campo Magnético 2^000000\nTipo: ^777777Suporte^000000\nDescrição:\n^008080Apenas com M.E.C.H.A.^000000\n^777777Bloqueia certos danos físicos\na distância e aumenta a DEF e DEFM\ndos alvos na área de 5x5 células.^000000\n^000088Consome 1 Gasolina.\nPrecisa de 1 Gerador de Barreira.^000000\nNível l Duração l DEF e DEFM\n[Nv 1]: ^77777730 segundos^000000 l ^777777+15%^000000\n[Nv 2]: ^77777745 segundos^000000 l ^777777+20%^000000\n[Nv 3]: ^77777760 segundos^000000 l ^777777+25%^000000" },
  "New Poison Research": { id: 2024, label: "Pesquisa de Toxinas", description: "Pesquisa de Toxinas ^777777(Research Poison)^000000\nNível máximo: ^77777710^000000\nTipo: ^777777Passiva^000000\nDescrição:\n^777777Aprende a criar novos tipos de veneno.\nAumentar o nível da habilidade aumenta em\n15 segundos de duração do Veneno Mortal.^000000\nNível l Chance l Toxina\n[Nv 1]: ^77777735%^000000 l ^777777Curare^000000\n[Nv 2]: ^77777740%^000000 l ^777777Pirexia^000000\n[Nv 3]: ^77777745%^000000 l ^777777Squamata^000000\n[Nv 4]: ^77777750%^000000 l ^777777Vipera^000000\n[Nv 5]: ^77777755%^000000 l ^777777Antídoto^000000\n[Nv 6]: ^77777760%^000000 l ^777777Beladona^000000\n[Nv 7]: ^77777765%^000000 l ^777777Waraitake^000000\n[Nv 8]: ^77777770%^000000 l ^777777Cicuta^000000\n[Nv 9]: ^77777775%^000000 l ^777777Oblivium^000000\n[Nv 10]: ^77777780%^000000" },
  "Ninja Aura": { id: 543, label: "Aura Ninja", description: "Aura Ninja ^777777(Ninja Aura)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Perícia Ninja 5^000000\nTipo: ^777777Suporte^000000\nDescrição:\n^777777Drena 5% do HP máx. para ativar a Aura.\nAumenta a FOR e INT, além de permitir o\nuso de Imagem Falsa e Ataque Mortal.^000000\nNível l FOR e INT l Duração\n[Nv 1]: ^777777+1^000000 l ^77777730 segundos^000000\n[Nv 2]: ^777777+2^000000 l ^77777745 segundos^000000\n[Nv 3]: ^777777+3^000000 l ^77777760 segundos^000000\n[Nv 4]: ^777777+4^000000 l ^77777775 segundos^000000\n[Nv 5]: ^777777+5^000000 l ^77777790 segundos^000000" },
