  "PFI": { id: 5401, label: "A.D.P", description: "A.D.P (Arma de Defesa Pessoal)\nMAX Lv : 10\n^777777Skill requirement : Basic Skill^000000\nSkill form : ^000099Passive^000000\nDetails: ^777777When equipped with a firearm-type weapon, P.ATK increases.^000000\n^ffffff_^000000\n[Lv 1] : ^777777P.ATK + 3^000000\n[Lv 2] : ^777777P.ATK + 4^000000\n[Lv 3] : ^777777P.ATK + 5^000000\n[Lv 4] : ^777777P.ATK + 6^000000\n[Lv 5] : ^777777P.ATK + 7^000000\n[Lv 6] : ^777777P.ATK + 8^000000\n[Lv 7] : ^777777P.ATK + 9^000000\n[Lv 8] : ^777777P.ATK + 10^000000\n[Lv 9] : ^777777P.ATK + 11^000000\n[Lv10] : ^777777P.ATK + 12^000000" },
  "Intensive Aim": { id: 5403, label: "Mira Focalizada", description: "Mira Focalizada\nMAX Lv : 1\n^777777Skill requirement : P.F.I 1^000000\nSkill form : ^993300Active(Toggle)^000000\nType : ^777777Buff^000000\nTarget : ^777777Instant Cast^000000\nDetails: ^777777When using skill, switches to focused aiming mode.\nMovement is impossible while focused aiming, and the aiming count accumulates by 1 every 0.5 seconds.\nThe aiming count accumulates up to 10, and if you leave the current cell due to an effect such as knockback or cancel the aiming state, the aiming count is reset.\nAtk/Hit/Cri increases in focused aiming mode.^000000\n^ffffff_^000000\n[Lv 1] : ^777777Atk +150/Hit +250/Cri +30 when aiming mode is active.^000000" },
  "Grenade Fragment": { id: 5404, label: "Fragmentação", description: "Fragmentação\nMAX Lv : 7\n^777777Skill requirement : Grenade Mastery 1^000000\nSkill form : ^993300Active^000000\nType : ^777777Supportive^000000\nTarget : ^777777Self^000000\nDetails : ^777777Applies elemental powder on the surface of throwing grenade, endows elemental property to it.\nWhen using skill level 7, the endowment is canceled.^000000\n^ffffff_^000000\n[Lv 1]: ^777777Gives water property to grenade^000000\n[Lv 2]: ^777777Gives wind property to grenade^000000\n[Lv 3]: ^777777Gives earth property to grenade^000000\n[Lv 4]: ^777777Gives fire property to grenade^000000\n[Lv 5]: ^777777Gives shadow property to grenade^000000\n[Lv 6]: ^777777Gives holy property to grenade^000000\n[Lv 7]: ^777777Remove property from grenade^000000" },
  "Debuff_Spore Explosion": {  },
  "Solar Luminance": { id: 2590, label: "Luz Solar", description: "Luz Solar ^777777(Light of Sun)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Explosão Solar 3^000000\nTipo: ^777777Suporte^000000 / ^CD3278Solar^000000\nDescrição:\n^777777Atrai o brilho do sol, aumentando o dano\nde [Explosão Solar] temporariamente.\nNão pode ser usada em conjunto com\nLuz Lunar e Luz Estelar.^000000\nNível l Bônus l Duração\n[Nv 1]: ^777777Dano +5%^000000 l ^77777720 segundos^000000\n[Nv 2]: ^777777Dano +10%^000000 l ^77777730 segundos^000000\n[Nv 3]: ^777777Dano +15%^000000 l ^77777740 segundos^000000\n[Nv 4]: ^777777Dano +20%^000000 l ^77777750 segundos^000000\n[Nv 5]: ^777777Dano +25%^000000 l ^77777760 segundos^000000" },
  "Solar Stance": { id: 2591, label: "Postura Solar", description: "Postura Solar ^777777(Sun Stance)^000000\nNível máximo: ^7777773^000000\nPré-requisitos: ^777777Registro SLE 1^000000\nTipo: ^777777Ativa^000000 / ^CD3278Solar^000000\nDescrição:\n^777777Permite usar as novas habilidades Solares.\nEnquanto estiver ativa, aumenta o ATQ.\nNão pode ser usada em conjunto com a\nPostura Lunar e a Postura Estelar.^000000\nNível l Bônus\n[Nv 1]: ^777777ATQ +3%^000000\n[Nv 2]: ^777777ATQ +4%^000000\n[Nv 3]: ^777777ATQ +5%^000000" },
  "Song Of Mana": { id: 2427, label: "Canção de Alfheim", description: "Canção de Alfheim ^777777(Song of Mana)^000000\nNível máximo: ^7777775^000000\nPré-requisitos:\n^777777Ritmo Contagiante 1, Balada Sinfônica 1 e\nSerenata ao Luar 1^000000 ou\n^777777Harmonizar 1, Canção de Balder 1 e\nSinfonia dos Ventos 1^000000\nTipo: ^777777Suporte^000000 / ^CD3278Coral^000000\nDescrição:\n^008080Apenas Chicotes ou Instrumentos.^000000\n^777777Recupera o SP instantaneamente e acelera\na regeneração natural de SP.\nDura 120 segundos e afeta membros do\ngrupo ao redor do usuário.\nO bônus é afetado por [Domínio Musical].^000000\n^000088Consome 1 Pastilha Refrescante.^000000\nNível l Área l SP curado l Regen. de SP\n[Nv 1]: ^77777711x11 células^000000 l ^77777710%^000000 l ^77777750%^000000\n[Nv 2]: ^77777713x13 células^000000 l ^77777710%^000000 l ^777777100%^000000\n[Nv 3]: ^77777715x15 células^000000 l ^77777715%^000000 l ^777777150%^000000\n[Nv 4]: ^77777717x17 células^000000 l ^77777715%^000000 l ^777777200%^000000\n[Nv 5]: ^77777719x19 células^000000 l ^77777720%^000000 l ^777777250%^000000" },
  "Research Report": { id: 5347, label: "Eureka", description: "Eureka ^777777(Research Report)^000000\nNível máximo: ^7777771^000000\nPré-requisitos:\n    ^777777Atirar Ácido Inflamável 3,\n    Atirar Ácido Álgido 3^000000\nTipo: ^777777Ativa^000000\nCusto de AP: ^FF0000100^000000\nDescrição:\n^777777Faz uma decoberta e cria um reporte disso.\nEnquanto estiver sob o efeito da Eureka,\naumenta o dano das habilidades de ácido\nde acordo com seu nível de base e POD.\nElas também causarão mais dano contra\noponentes das raças Amorfo e Planta.\nO consumo dos Ácidos passa a ser de 1.^000000\nHabilidades afetadas:\n^777777Atirar Ácido Sólido\nAtirar Ácido Álgido\nAtirar Ádicdo Gasoso\nAtirar Ácido Inflamável^000000" },
  "Soul Cutter": { id: 3005, label: "Corte Espiritual", description: "Corte Espiritual ^777777(Soul Cutter)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Impacto Cruzado 2^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Causa dano físico corpo a corpo.\nAlvos com espírito de Espiritualistas terão\ndano adicional, cancelando o espírito.^000000\nNível l ATQ\n[Nv 1]: ^777777100%^000000\n[Nv 2]: ^777777200%^000000\n[Nv 3]: ^777777300%^000000\n[Nv 4]: ^777777400%^000000\n[Nv 5]: ^777777500%^000000" },
  "Soul Drain": { id: 364, label: "Dreno de Alma", description: "Dreno de Alma ^777777(Soul Drain)^000000\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Espíritos Anciões 7,\nAumentar Recuperação de SP 5^000000\nTipo: ^777777Passiva^000000\nDescrição:\n^777777Aumenta o SP máx. do usuário.\nAo derrotar monstros com magias de\nalvo único, recupera um pouco de SP.\nO SP recuperado varia com o nv. do alvo.\nNão funciona com monstros do tipo Chefe.^000000\nNível l SP máx.\n[Nv 1]: ^777777+2%^000000\n[Nv 2]: ^777777+4%^000000\n[Nv 3]: ^777777+6%^000000\n[Nv 4]: ^777777+8%^000000\n[Nv 5]: ^777777+10%^000000\n[Nv 6]: ^777777+12%^000000\n[Nv 7]: ^777777+14%^000000\n[Nv 8]: ^777777+16%^000000\n[Nv 9]: ^777777+18%^000000\n[Nv 10]: ^777777+20%^000000" },
