  "Wrath of": { id: 437, label: "Fúria Estelar", description: "Fúria Estelar ^777777(Star Anger)^000000\nNível máximo: ^7777773^000000\nPré-requisitos:\n^777777Oposição Solar, Lunar e Estelar 3^000000\nTipo: ^777777Passiva^000000\nDescrição:\n^777777Melhora o ATQ contra alvos Estelares.\nAumentar o nv. da habilidade melhora o ATQ\nbaseado na FOR, SOR, DES e nível base.^000000" },
  "Empty Shadow": { id: 3024, label: "Vazio das Sombras", description: "Vazio das Sombras ^777777(Empty Shadow)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Esmagamento Sombrio 2^000000\nTipo: ^777777Ativa^000000\nDescrição:\n^777777Desativa a reflexão de dano físico e mágico.\nEnquanto estiver ativa, alvos que tentarem\nconjurar alguma habilidade de reflexão\nterão uma pequena chance de falha.^000000\n^000088Consome 1 Pedra da Sombra.^000000\nNível l Duração\n[Nv 1]: ^77777710 segundos^000000\n[Nv 2]: ^77777715 segundos^000000\n[Nv 3]: ^77777720 segundos^000000\n[Nv 4]: ^77777725 segundos^000000\n[Nv 5]: ^77777730 segundos^000000" },
  "Wug Rider": { id: 2241, label: "Montaria em Worg", description: "Montaria em Worg ^777777(Worg Rider)^000000\nNível máximo: ^7777773^000000\nPré-requisitos: ^777777Adestrar Worg 1^000000\nTipo: ^777777Ativa^000000\nDescrição:\n^777777Permite montar em um Worg.\nEnquanto montado, não é possível\natacar com arco. Apenas pegar itens,\nusar armadilhas e habilidades do Worg.\nO movimento é acelerado enquanto monta.^000000" },
