  "Arrow Storm": { id: 2233, label: "Tempestade de Flechas", description: "Tempestade de Flechas ^777777(Arrow Storm)^000000\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Disparo Certeiro 5^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Causa dano físico a distância na área.\nO dano é afetado pelo nível de base do\nusuário e ganha um bônus se a habilidade\n[Disparo Selvagem] estiver ativada.^000000\n^000088Consome 5 flechas.^000000\nNível l ATQ l ATQ (Bônus) l Área\n[Nv 1]: ^777777380%^000000 l ^777777450%^000000 l ^7777775x5 células^000000\n[Nv 2]: ^777777560%^000000 l ^777777700%^000000 l ^7777775x5 células^000000\n[Nv 3]: ^777777740%^000000 l ^777777950%^000000 l ^7777775x5 células^000000\n[Nv 4]: ^777777920%^000000 l ^7777771.200%^000000 l ^7777775x5 células^000000\n[Nv 5]: ^7777771.100%^000000 l ^7777771.450%^000000 l ^7777775x5 células^000000\n[Nv 6]: ^7777771.280%^000000 l ^7777771.700%^000000 l ^7777777x7 células^000000\n[Nv 7]: ^7777771.460%^000000 l ^7777771.950%^000000 l ^7777777x7 células^000000\n[Nv 8]: ^7777771.640%^000000 l ^7777772.200%^000000 l ^7777777x7 células^000000\n[Nv 9]: ^7777771.820%^000000 l ^7777772.450%^000000 l ^7777777x7 células^000000\n[Nv 10]: ^7777772.000%^000000 l ^7777772.700%^000000 l ^7777779x9 células^000000" },
  "Arrow Vulcan": { id: 394, label: "Vulcão de Flechas", description: "Vulcão de Flechas ^777777(Arrow Vulcan)^000000\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Rajada de Flechas 5,\nChuva de Flechas 5, Flecha Melódica 1^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^008080Apenas Chicotes ou Instrumentos.^000000\n^777777Causa dano físico a distância no alvo.\nO nível de base influencia no dano causado.^000000\n^000088Consome 1 flecha.^000000\nNível l ATQ\n[Nv 1]: ^777777600%^000000\n[Nv 2]: ^777777700%^000000\n[Nv 3]: ^777777800%^000000\n[Nv 4]: ^777777900%^000000\n[Nv 5]: ^7777771.000%^000000\n[Nv 6]: ^7777771.100%^000000\n[Nv 7]: ^7777771.200%^000000\n[Nv 8]: ^7777771.300%^000000\n[Nv 9]: ^7777771.400%^000000\n[Nv 10]: ^7777771.500%^000000" },
  "Axe Boomerang": { id: 2278, label: "Arremesso de Machado", description: "Arremesso de Machado ^777777(Axe Boomerang)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Maestria com Machados 1^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Causa dano físico a distância\ne empurra o alvo para trás.\nO peso do machado afeta o dano.^000000\nNível l ATQ l Alcance\n[Nv 1]: ^777777300%^000000 l ^7777775 células^000000\n[Nv 2]: ^777777350%^000000 l ^7777776 células^000000\n[Nv 3]: ^777777400%^000000 l ^7777777 células^000000\n[Nv 4]: ^777777450%^000000 l ^7777778 células^000000\n[Nv 5]: ^777777500%^000000 l ^7777779 células^000000" },
  "Axe Stomp": { id: 5295, label: "Machado Esmagador", description: "Machado Esmagador ^777777(Axe Stomp)^000000\nNível máximo: ^7777775^000000\nPré-requisito: ^777777Defesa com Machado 5^000000\nTipo: ^777777Ofensiva^000000\nRegen. de AP: ^0054FF3^000000\nDescrição:\n^008080Apenas com Machado.^000000\n^777777Causa dano físico corpo a corpo ao redor.\nNos próximos 10 segundos, aumenta o dano\nde [Fúria do Furacão] e se estiver usando\num Machado de Duas Mãos, atinge 3 vezes.\nNível de base e POD afetam o dano.^000000\nNível l ATQ l Área\n[Nv 1]: ^777777400%^000000 l ^7777773x3 células^000000\n[Nv 2]: ^777777800%^000000 l ^7777773x3 células^000000\n[Nv 3]: ^7777771.200%^000000 l ^7777775x5 células^000000\n[Nv 4]: ^7777771.600%^000000 l ^7777775x5 células^000000\n[Nv 5]: ^7777772.000%^000000 l ^7777777x7 células^000000" },
  "Axe Tornado": { id: 2280, label: "Fúria do Furacão ", description: "Fúria do Furacão ^777777(Axe Tornado)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Maestria com Machados 1^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^008080Apenas com Machados.^000000\n^777777Causa dano físico corpo a corpo ao redor.\nVIT e nível de base influenciam no dano.^000000\nNível l ATQ l Área\n[Nv 1]: ^777777380%^000000 l ^7777775x5 células^000000\n[Nv 2]: ^777777560%^000000 l ^7777775x5 células^000000\n[Nv 3]: ^777777740%^000000 l ^7777777x7 células^000000\n[Nv 4]: ^777777920%^000000 l ^7777777x7 células^000000\n[Nv 5]: ^7777771.100%^000000 l ^7777777x7 células^000000" },
  "Kunai - Nightmare": { id: 5494, label: "Kunai do Pesadelo", description: "Kunai do Pesadelo\nMAX Lv : 1\n^777777Skill requirement : Kunai - Distortion 5, Kunai - Rotation 5, Kunai - Refraction 5^000000\nSkill form : ^3F0099Active(AP)^000000\nType : ^777777Range Physical^000000\nTarget : ^777777Instant Cast^000000\nConsumes : ^FF0000AP 30^000000\nDetails: ^777777Disperses numerous hidden weapons to all enemies within a 13x13 cell range, inflicting powerful long range physical damage.\nInflicts 1.5 times more damage to targets affected by the nightmare effect (the nightmare effect is canceled).\nDamage is additionally increased depending on the caster's base level and POW.^000000\n^ffffff_^000000\n[Lv 1] : ^777777ATK 15000%^000000" },
