  "Cold Slower": { id: 2260, label: "Gás Criogênico", description: "Gás Criogênico ^777777(Ice Launcher)^000000\nNível máximo: ^7777773^000000\nPré-requisitos: ^777777Metralhadora 3^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^008080Apenas com M.E.C.H.A.^000000\n^777777Causa dano físico de\npropriedade Água com chance de\ninfligir [Hipotermia] ou\n[Congelamento] na área.^000000\n^000088Consome 1 Gasolina.\nConsome 1 Cápsula de Nitrogênio.^000000\nNível l Área l ATQ\n[Nv 1]: ^7777775x5 células^000000 l ^777777600%^000000\n[Nv 2]: ^7777777x7 células^000000 l ^777777900%^000000\n[Nv 3]: ^7777779x9 células^000000 l ^7777771.200%^000000" },
  "Combo Finish": { id: 273, label: "O Último Dragão", description: "O Último Dragão ^777777(Combo Finish)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Combo Quádruplo 3^000000\nTipo: ^777777Ofensiva^000000 / ^CD3278Combo^000000\nDescrição:\n^008080Após Combo Quádruplo.^000000\n^777777Causa dano físico corpo a corpo no alvo.\nO dano é afetado pela FOR do usuário.\nApós o uso, haverá 0,3 segundos para usar\nPunho Supremo de Asura em Fúria Interior e\nsobrando pelo menos 1 Esfera Espiritual.^000000\n^000088Consome 1 Esfera Espiritual.^000000\nNível l ATQ l Custo de SP\n[Nv 1]: ^777777600%^000000 l ^7777773^000000\n[Nv 2]: ^777777750%^000000 l ^7777774^000000\n[Nv 3]: ^777777900%^000000 l ^7777775^000000\n[Nv 4]: ^7777771.050%^000000 l ^7777776^000000\n[Nv 5]: ^7777771.200%^000000 l ^7777777^000000" },
  "Comet": { id: 2213, label: "Cometa", description: "Cometa ^777777(Comet)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Chamas de Hela 3^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Abre espaço para um enorme Cometa cair,\ncausando dano mágico de propriedade Neutro\nna área de 13x13 células e infligindo um\nefeito de [Vício Mágico] nos oponentes.^000000\nVício Mágico:\n^777777Por 20 segundos, reduz a resistência aos\nataques de todas as propriedades em 50%.^000000\nNível l ATQM l Custo de SP\n[Nv 1]: ^7777773.200%^000000 l ^77777770^000000\n[Nv 2]: ^7777773.900%^000000 l ^77777790^000000\n[Nv 3]: ^7777774.600%^000000 l ^777777110^000000\n[Nv 4]: ^7777775.300%^000000 l ^777777130^000000\n[Nv 5]: ^7777776.000%^000000 l ^777777150^000000" },
  "Conflagration": { id: 5372, label: "Conflagração", description: "Conflagração ^000000(Conflagration)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Estudo Elemental 2^000000\nTipo: ^777777Ofensiva^000000\nRegen. de AP: ^0054FF5^000000\nDescrição:\n^777777Provoca um incêndio na área de 9x9 células\nque dura 3 segundos, causando dano mágico\nde propriedade Fogo a cada 0,3 segundo.\nTem chance de infligir [Ardência].\nO dano aumenta se Ardor for invocado.\nNível de base e FEI influenciam o dano.^000000\nNível l ATQM l ATQM (Ardor) l Chance\n[Nv 1]: ^777777400%^000000 l ^777777800%^000000 l ^77777720%^000000\n[Nv 2]: ^777777800%^000000 l ^7777771.600%^000000 l ^77777730%^000000\n[Nv 3]: ^7777771.200%^000000 l ^7777772.400%^000000 l ^77777740%^000000\n[Nv 4]: ^7777771.600%^000000 l ^7777773.200%^000000 l ^77777750%^000000\n[Nv 5]: ^7777772.000%^000000 l ^7777774.000%^000000 l ^77777760%^000000" },
  "Counter Slash": { id: 2029, label: "Retaliação", description: "Retaliação ^777777(Counter Slash)^000000\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Reflexo de Combate 1^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^008080Após ativar [Reflexo de Combate].^000000\n^777777Causa dano físico corpo a corpo que ignora\na DEF dos oponentes ao redor do usuário.\nAGI e Nv. de base/classe afetam o dano.^000000\nNível l ATQ l Área\n[Nv 1]: ^777777450%^000000 l ^7777773x3 células^000000\n[Nv 2]: ^777777600%^000000 l ^7777773x3 células^000000\n[Nv 3]: ^777777750%^000000 l ^7777773x3 células^000000\n[Nv 4]: ^777777900%^000000 l ^7777773x3 células^000000\n[Nv 5]: ^7777771.050%^000000 l ^7777773x3 células^000000\n[Nv 6]: ^7777771.200%^000000 l ^7777775x5 células^000000\n[Nv 7]: ^7777771.350%^000000 l ^7777775x5 células^000000\n[Nv 8]: ^7777771.500%^000000 l ^7777775x5 células^000000\n[Nv 9]: ^7777771.650%^000000 l ^7777775x5 células^000000\n[Nv 10]: ^7777771.800%^000000 l ^7777775x5 células^000000" },
  "Crazy Weed": { id: 2483, label: "Erva Daninha", description: "Erva Daninha ^777777(Crazy Vines)^000000\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Muralha de Espinhos 3^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Espalha ervas daninhas na área escolhida.\nCausa dano físico a distância e remove\nalgumas magias de solo atuantes no lugar.\nO dano é afetado pelo seu nível de base.^000000\n^000088Consome 1 Semente de Planta Selvagem.^000000\nNível l Ervas l ATQ por erva\n[Nv 1]: ^7777775^000000 l ^777777800%^000000\n[Nv 2]: ^7777776^000000 l ^777777900%^000000\n[Nv 3]: ^7777776^000000 l ^7777771.000%^000000\n[Nv 4]: ^7777777^000000 l ^7777771.100%^000000\n[Nv 5]: ^7777777^000000 l ^7777771.200%^000000\n[Nv 6]: ^7777778^000000 l ^7777771.300%^000000\n[Nv 7]: ^7777778^000000 l ^7777771.400%^000000\n[Nv 8]: ^7777779^000000 l ^7777771.500%^000000\n[Nv 9]: ^7777779^000000 l ^7777771.600%^000000\n[Nv 10]: ^77777710^000000 l ^7777771.700%^000000" },
