  "Cross Ripper Slasher": { id: 2037, label: "Castigo de Loki", description: "Castigo de Loki ^777777(Cross Ripper Slasher)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Lâminas de Loki 1^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^008080Apenas com Katar.^000000\n^777777Só pode ser usada com Pontos de Rotação\nacumulados por [Lâminas de Loki].\nCausa dano físico a distância no alvo.\nA AGI e o nível de base influenciam no dano.^000000\nNível l ATQ l Alcance\n[Nv 1]: ^77777780% + Rotação^000000 l ^7777779 células^000000\n[Nv 2]: ^777777160% + Rotação^000000 l ^77777710 células^000000\n[Nv 3]: ^777777240% + Rotação^000000 l ^77777711 células^000000\n[Nv 4]: ^777777320% + Rotação^000000 l ^77777712 células^000000\n[Nv 5]: ^777777400% + Rotação^000000 l ^77777713 células^000000" },
  "Cross Slash": { id: 3004, label: "Impacto Cruzado", description: "Impacto Cruzado ^777777(Cross Slash)^000000\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Refúgio das Sombras 1^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^008080Apenas com as duas mãos armadas.^000000\n^777777Pula em direção ao alvo para causar dano\nfísico a distância e deixar a [Ferida Cruzada].\nNos próximos 3 segundos, o alvo sofrerá\nmais dano de [Impacto Cruzado].\nO nível de base do usuário aumenta o dano.^000000\nNível l ATQ l Alcance l Recarga\n[Nv 1]: ^777777200%^000000 l ^7777774 células^000000 l ^7777774,0 segundos^000000\n[Nv 2]: ^777777400%^000000 l ^7777774 células^000000 l ^7777773,9 segundos^000000\n[Nv 3]: ^777777600%^000000 l ^7777774 células^000000 l ^7777773,8 segundos^000000\n[Nv 4]: ^777777800%^000000 l ^7777775 células^000000 l ^7777773,7 segundos^000000\n[Nv 5]: ^7777771.000%^000000 l ^7777775 células^000000 l ^7777773,6 segundos^000000\n[Nv 6]: ^7777771.200%^000000 l ^7777775 células^000000 l ^7777773,5 segundos^000000\n[Nv 7]: ^7777771.400%^000000 l ^7777776 células^000000 l ^7777773,4 segundos^000000\n[Nv 8]: ^7777771.600%^000000 l ^7777776 células^000000 l ^7777773,3 segundos^000000\n[Nv 9]: ^7777771.800%^000000 l ^7777776 células^000000 l ^7777773,2 segundos^000000\n[Nv 10]: ^7777772.000%^000000 l ^7777777 células^000000 l ^7777773,1 segundos^000000" },
