  "Dragon Breath - WATER": { id: 5004, label: "Bafo do Dragão", description: "Bafo do Dragão ^777777(Water Dragon Breath)^000000\nNível máximo: ^77777710^000000\nPré requisito: ^777777Adestrar Dragão 2^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^008080Apenas com montaria de Dragão.^000000\n^777777O dragão bafora na área selecionada,\npodendo infligir [Hipotermia] e causar dano\nfísico a distância de propriedade Água.\nA propriedade pode ser alterada de acordo\ncom a Runa ativa. Luxanima tem sempre\nprioridade se duas runas estiverem ativas.^000000\nNormal: ^777777Propriedade Água.^000000\nRuna Othila: ^777777Propriedade Fantasma.^000000\nRuna Luxanima: ^777777Propriedade Neutro.^000000" },
  "Dragon Breath": { id: 2008, label: "Sopro do Dragão", description: "Sopro do Dragão ^777777(Dragon Breath)^000000\nNível máximo: ^77777710^000000\nPré requisito: ^777777Adestrar Dragão 2^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^008080Apenas com montaria de Dragão.^000000\n^777777O dragão sopra na área selecionada,\npodendo infligir [Incêndio] e causar dano\nfísico a distância de propriedade Fogo.\nA propriedade pode ser alterada de acordo\ncom a Runa ativa. Luxanima tem sempre\nprioridade se duas runas estiverem ativas.^000000\nNormal: ^777777Propriedade Fogo.^000000\nRuna Turisaz: ^777777Propriedade Sagrado.^000000\nRuna Luxanima: ^777777Propriedade Sombrio.^000000" },
  "Dragon Combo": { id: 2326, label: "Punho do Dragão", description: "Punho do Dragão ^777777(Dragon Combo)^000000\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Combo Triplo 5^000000\nTipo: ^777777Ofensiva^000000 / ^CD3278Combo^000000\nDescrição:\n^777777Dá um soco no alvo, causando dano físico\ncorpo a corpo com chance de Atordoamento.\nApós o golpe, pode usar [Ruína] em combo.^000000\nNível l ATQ l Chance de atordoar\n[Nv 1]: ^777777180%^000000 l ^7777772%^000000\n[Nv 2]: ^777777260%^000000 l ^7777773%^000000\n[Nv 3]: ^777777340%^000000 l ^7777774%^000000\n[Nv 4]: ^777777420%^000000 l ^7777775%^000000\n[Nv 5]: ^777777500%^000000 l ^7777776%^000000\n[Nv 6]: ^777777580%^000000 l ^7777777%^000000\n[Nv 7]: ^777777660%^000000 l ^7777778%^000000\n[Nv 8]: ^777777740%^000000 l ^7777779%^000000\n[Nv 9]: ^777777820%^000000 l ^77777710%^000000\n[Nv 10]: ^777777900%^000000 l ^77777711%^000000" },
  "Dragon Tail": { id: 2566, label: "Lançar Míssil", description: "Lançar Míssil ^777777(Dragon Tail)^000000\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Marcar em Brasa 1,\nArremessar Granada 3^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^008080Apenas com Lança-Granadas.^000000\n^777777Lança a Cauda do Dragão no alvo, atingindo\noponentes próximos e causando dano físico\na distância. Alvos com a [Marca de Brasa]\nreceberão dano adicional, assim como os\noponentes ao redor do alvo marcado.^000000\n^000088Consome 1 Míssil Cauda de Dragão.^000000\nNível l ATQ l ATQ (alvo marcado)\n[Nv. 1]: ^777777700%^000000 l ^7777771.400%^000000\n[Nv. 2]: ^777777900%^000000 l ^7777771.800%^000000\n[Nv. 3]: ^7777771.100%^000000 l ^7777772.200%^000000\n[Nv. 4]: ^7777771.300%^000000 l ^7777772.600%^000000\n[Nv. 5]: ^7777771.500%^000000 l ^7777773.000%^000000\n[Nv. 6]: ^7777771.700%^000000 l ^7777773.400%^000000\n[Nv. 7]: ^7777771.900%^000000 l ^7777773.800%^000000\n[Nv. 8]: ^7777772.100%^000000 l ^7777774.200%^000000\n[Nv. 9]: ^7777772.300%^000000 l ^7777774.600%^000000\n[Nv. 10]: ^7777772.500%^000000 l ^7777775.000%^000000" },
