  "Earth Drive": { id: 2323, label: "Aegis Inferi", description: "Aegis Inferi ^777777(Earth Drive)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Escudo Supressor 3^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^008080Apenas com Escudo.^000000\n^777777Causa dano físico corpo a corpo na área,\nincluindo oponentes escondidos e removendo\nhabilidades mágicas atuantes no terreno.\nA FOR, VIT e nv. de base afetam o dano.\nA propriedade varia de acordo com a arma.^000000\nNível l ATQ l Área\n[Nv 1]: ^777777380%^000000 l ^7777773x3 células^000000\n[Nv 2]: ^777777760%^000000 l ^7777773x3 células^000000\n[Nv 3]: ^7777771.140%^000000 l ^7777775x5 células^000000\n[Nv 4]: ^7777771.520%^000000 l ^7777775x5 células^000000\n[Nv 5]: ^7777771.900%^000000 l ^7777777x7 células^000000" },
  "Earth Grave": { id: 2446, label: "Castigo de Nerthus", description: "Castigo de Nerthus ^777777(Earth Grave)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Coluna de Pedra 5^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Causa dano mágico de propriedade Terra com\nchance de infligir Sangramento na área.\nPode atingir oponentes em Esconderijo.\nO dano é afetado pela INT, nível de base e\npelo nível de Encantar com Terremoto.^000000\nNível l Área\n[Nv 1]: ^7777777x7 células^000000\n[Nv 2]: ^7777777x7 células^000000\n[Nv 3]: ^7777777x7 células^000000\n[Nv 4]: ^7777779x9 células^000000\n[Nv 5]: ^7777779x9 células^000000" },
  "Earth Shaker": { id: 2328, label: "Impacto Sísmico", description: "Impacto Sísmico ^777777(Earth Shaker)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Punho do Dragão 3^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Causa dano físico corpo a corpo na área.\nMonstros atingidos ficarão impactados por\n5 segundos, fazendo com que recebam mais\ndano da habilidade [Explosão Espiritual].\nOponentes ocultos receberão dano maior.\nO dano é afetado pela FOR e Nv. de base.^000000\nNível l ATQ l ATQ (escondido) l Área\n[Nv 1]: ^777777300%^000000 l ^777777400%^000000 l ^7777773x3 células^000000\n[Nv 2]: ^777777600%^000000 l ^777777800%^000000 l ^7777775x5 células^000000\n[Nv 3]: ^777777900%^000000 l ^7777771.200%^000000 l ^7777777x7 células^000000\n[Nv 4]: ^7777771.200%^000000 l ^7777771.600%^000000 l ^7777779x9 células^000000\n[Nv 5]: ^7777771.500%^000000 l ^7777772.000%^000000 l ^77777711x11 células^000000" },
  "Earth Spike": { id: 90, label: "Coluna de Pedra", description: "Coluna de Pedra ^777777(Earth Spike)^000000\nNível máximo: ^7777775^000000\nPré requisitos (^008080Bruxos^000000): ^777777Petrificar 1^000000\nPré requisitos (^008080Sábios^000000):\n^777777Encantar com Terremoto 1^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Ergue espetos de pedra no alvo, causando\n200% de dano mágico de propriedade Terra\npara cada espeto erguido do chão.^000000\nNível l Espetos\n[Nv 1]: ^7777771^000000\n[Nv 2]: ^7777772^000000\n[Nv 3]: ^7777773^000000\n[Nv 4]: ^7777774^000000\n[Nv 5]: ^7777775^000000" },
