  "Elemental Buster": { id: 5380, label: "Círculo Elemental", description: "Círculo Elemental ^777777(Elemental Buster)^000000\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Invocar Terremotus 1,\n    Invocar Ardor 1, Invocar Procella 1,\n    Invocar Diluvium 1, Invocar Serpens 1,\n    Maestria Elemental 5^000000\nTipo: ^777777Ofensiva^000000\nCusto de AP: ^FF0000150^000000\nDescrição:\n^008080Apenas com Elemental evoluído.^000000\n^777777Causa dano mágico em 13x13 células.\nA propriedade é igual ao Elemental ativo.\nInflige mais dano contra Dragão e Amorfo.\nNível de base e FEI influenciam o dano.^000000\nNível l ATQM l ATQM (Dragão e Amorfo)\n[Nv 1]: ^777777480%^000000 l ^7777771.100%^000000\n[Nv 2]: ^777777960%^000000 l ^7777772.200%^000000\n[Nv 3]: ^7777771.440%^000000 l ^7777773.300%^000000\n[Nv 4]: ^7777771.920%^000000 l ^7777774.400%^000000\n[Nv 5]: ^7777772.400%^000000 l ^7777775.500%^000000\n[Nv 6]: ^7777772.880%^000000 l ^7777776.600%^000000\n[Nv 7]: ^7777773.360%^000000 l ^7777777.700%^000000\n[Nv 8]: ^7777773.840%^000000 l ^7777778.800%^000000\n[Nv 9]: ^7777774.320%^000000 l ^7777779.900%^000000\n[Nv 10]: ^7777774.800%^000000 l ^77777711.000%^000000" },
  "Envenom": { id: 52, label: "Envenenar", description: "Envenenar ^777777(Envenom)^000000\nNível máximo: ^77777710^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Causa dano físico corpo a corpo\nde propriedade Veneno, com chances de\ninfligir [Envenenamento] no alvo.\nO dano causado é igual ao ataque básico\nadicionado ao bônus da habilidade.^000000\nNível l Dano l Chance\n[Nv 1]: ^777777+15^000000 l ^77777714%^000000\n[Nv 2]: ^777777+30^000000 l ^77777718%^000000\n[Nv 3]: ^777777+45^000000 l ^77777722%^000000\n[Nv 4]: ^777777+60^000000 l ^77777726%^000000\n[Nv 5]: ^777777+75^000000 l ^77777730%^000000\n[Nv 6]: ^777777+90^000000 l ^77777734%^000000\n[Nv 7]: ^777777+105^000000 l ^77777738%^000000\n[Nv 8]: ^777777+120^000000 l ^77777742%^000000\n[Nv 9]: ^777777+135^000000 l ^77777746%^000000\n[Nv 10]: ^777777+150^000000 l ^77777750%^000000" },
  "Esma": { id: 469, label: "Esma", description: "Esma\nNível máximo: ^77777710^000000\nTipo: ^777777Ofensiva^000000\nAlvo: ^777777Apenas monstros^000000\nPré-requisitos: ^777777Estin 7, Estun 7^000000\nDescrição:\n^777777Após conjurar Estin, Estun ou Eske, você terá\n3 segundos para invocar círculos espirituais\nque causam dano mágico num único alvo.\nA propriedade muda conforme Brisa Leve.^000000\nNível l Círculos l Custo de SP\n[Nv 1] ^7777771^000000 l ^7777778^000000\n[Nv 2] ^7777772^000000 l ^77777716^000000\n[Nv 3] ^7777773^000000 l ^77777724^000000\n[Nv 4] ^7777774^000000 l ^77777732^000000\n[Nv 5] ^7777775^000000 l ^77777740^000000\n[Nv 6] ^7777776^000000 l ^77777748^000000\n[Nv 7] ^7777777^000000 l ^77777756^000000\n[Nv 8] ^7777778^000000 l ^77777764^000000\n[Nv 9] ^7777779^000000 l ^77777772^000000\n[Nv 10] ^7777710^000000 l ^77777780^000000" },
  "Espa": { id: 2602, label: "Espa", description: "Espa\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Esha 1^000000\nTipo: ^777777Ofensiva^000000\nAlvo: ^777777Apenas monstros^000000\nDescrição:\n^777777Causa dano mágico em um alvo único.\n5 segundos após o uso, pode usar [Eswhoo]\nA propriedade é alterada por Brisa Leve.\nO dano é aumentado pelo seu nível de base.^000000\nNo nível 10, não consome Almas.\n^008080Consome 1 Alma.^000000\nNível l ATQM\n[Nv 1]: ^777777750%^000000\n[Nv 2]: ^7777771.000%^000000\n[Nv 3]: ^7777771.250%^000000\n[Nv 4]: ^7777771.500%^000000\n[Nv 5]: ^7777771.750%^000000\n[Nv. 6]: ^7777772.000%^000000\n[Nv. 7]: ^7777772.250%^000000\n[Nv. 8]: ^7777772.500%^000000\n[Nv. 9]: ^7777772.750%^000000\n[Nv. 10]: ^7777773.000%^000000" },
  "Eswhoo": { id: 2604, label: "Eswhoo", description: "Eswhoo\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Espa 3^000000\nTipo: ^777777Ofensiva^000000\nAlvo: ^777777Apenas monstros^000000\nDescrição:\n^CD3278Somente após Espa.^000000\n^777777Causa dano mágico na área selecionada.\nPode usar Esma até 5 segundos após o uso.\nA propriedade é alterada por Brisa Leve.\nO dano é aumentado pelo seu nível de base.\nNo nível 10, consome apenas 1 Alma.^000000\n^008080Consome 2 Almas.^000000\nNível l ATQM l Área\n[Nv. 1]: ^7777771.700%^000000 l ^7777773x3 células^000000\n[Nv. 2]: ^7777771.900%^000000 l ^7777773x3 células^000000\n[Nv. 3]: ^7777772.100%^000000 l ^7777773x3 células^000000\n[Nv. 4]: ^7777772.300%^000000 l ^7777775x5 células^000000\n[Nv. 5]: ^7777772.500%^000000 l ^7777775x5 células^000000\n[Nv. 6]: ^7777772.700%^000000 l ^7777775x5 células^000000\n[Nv. 7]: ^7777772.900%^000000 l ^7777777x7 células^000000\n[Nv. 8]: ^7777773.100%^000000 l ^7777777x7 células^000000\n[Nv. 9]: ^7777773.300%^000000 l ^7777777x7 células^000000\n[Nv. 10]: ^7777773.500%^000000 l ^7777779x9 células^000000" },
  "Eternal Slash": { id: 5289, label: "Talho Eterno", description: "Talho Eterno ^777777(Eternal Slash)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Reflexo de Combate 3,\nSenso das Sombras 5, Adagas Voadoras 3^000000\nTipo: ^777777Ativa^000000\nDescrição:\n^008080Com [Reflexo de Combate] ativo.^000000\n^777777Causa dano físico corpo a corpo no alvo.\nSe usada novamente dentro de 3 segundos,\no número de golpes aumenta em até 5 vezes.\nNível de base e POD afetam o dano.\nTem possibilidade do ataque ser crítico.\nA chance é a metade de CRIT do usuário.^000000\nNível l ATQ\n[Nv 1]: ^777777350%^000000\n[Nv 2]: ^777777700%^000000\n[Nv 3]: ^7777771.050%^000000\n[Nv 4]: ^7777771.400%^000000\n[Nv 5]: ^7777771.750%^000000" },
  "Evil Soul Curse": { id: 2601, label: "Necromancia", description: "Necromancia ^777777(Soul Curse)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Ceifar Alma 3^000000\nTipo: ^777777Ativa^000000\nDescrição:\n^777777Joga uma praga para infligir Assombração\nno alvo e em oponentes 7x7 células ao redor.^000000\nAssombração:\n^777777Resistência a propriedade Sombrio -100%.\nEm monstros chefes, a redução é de 20%.^000000\n^000088Consome 3 Almas.^000000\nNível l Chance\n[Nv 1]: ^77777720%^000000\n[Nv 2]: ^77777740%^000000\n[Nv 3]: ^77777760%^000000\n[Nv 4]: ^77777780%^000000\n[Nv 5]: ^777777100%^000000" },
  "Exploding Dragon": { id: 536, label: "Dragão Explosivo", description: "Dragão Explosivo ^777777(Exploding Dragon)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Perícia Ninja 10,\nEscudo de Chamas 7^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Causa dano mágico de propriedade Fogo\nno alvo e na área de 5x5 células ao redor.\n^000088Consome 1 Pedra do Fogo.^000000\nNível l ATQM\n[Nv 1]: ^777777300%^000000\n[Nv 2]: ^777777450%^000000\n[Nv 3]: ^777777600%^000000\n[Nv 4]: ^777777750%^000000\n[Nv 5]: ^777777900%^000000" },
  "Explosion Blaster": { id: 5244, label: "Técnica da Mão Explosiva", description: "Técnica da Mão Explosiva ^777777(Blaster)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Oleum Sanctum 1^000000\nTipo: ^777777Ofensiva^000000\nRegen. de AP: ^0054FF4^000000\nDescrição:\n^777777Causa dano físico a distância no alvo e\nem oponentes ao redor dele.\nSe inimigos estiverem sofrendo o efeito de\n[Óleo Ungido] causa ainda mais dano.\nNível de base e POD influenciam no dano.\nTem chance do ataque ser crítico.\nA chance é igual ao CRIT do usuário.^000000\nNível l ATQ l ATQ (Óleo Ungido) l Área\n[Nv 1]: ^777777650%^000000 l ^777777850%^000000 l ^7777775x5 células^000000\n[Nv 2]: ^7777771.300%^000000 l ^7777771.700%^000000 l ^7777775x5 células^000000\n[Nv 3]: ^7777771.950%^000000 l ^7777772.550%^000000 l ^7777777x7 células^000000\n[Nv 4]: ^7777772.600%^000000 l ^7777773.400%^000000 l ^7777777x7 células^000000\n[Nv 5]: ^7777773.250%^000000 l ^7777774.250%^000000 l ^7777779x9 células^000000" },
