  "Frenzy Shot": { id: 5322, label: "Rajada Frenética", description: "Rajada Frenética ^777777(Frenzy Shot)^000000\nNível máximo: ^77777710^000000\nPré-requisito: ^777777Disparo em Cadeia 3,\n    Versatilidade 5^000000\nTipo: ^777777Ofensiva^000000\nRegen. de AP: ^0054FF1^000000\nDescrição:\n^008080Apenas com Arco.^000000\n^777777Causa dano físico a distância no oponente.\nHá uma chance de atingir mais 3 vezes.\nNível de base e CON aumentam o dano.\nA chance é igual ao CRIT do usuário.\nO dano é afetado pelo seu nível de base.^000000\n^000088Consome 3 Flechas.^000000\nNível l ATQ l Chance de 3 ataques\n[Nv 1]: ^777777350%^000000 l ^7777775%^000000\n[Nv 2]: ^777777700%^000000 l ^77777710%^000000\n[Nv 3]: ^7777771.050%^000000 l ^77777715%^000000\n[Nv 4]: ^7777771.400%^000000 l ^77777720%^000000\n[Nv 5]: ^7777771.750%^000000 l ^77777725%^000000\n[Nv 6]: ^7777772.100%^000000 l ^77777730%^000000\n[Nv 7]: ^7777772.450%^000000 l ^77777735%^000000\n[Nv 8]: ^7777772.800%^000000 l ^77777740%^000000\n[Nv 9]: ^7777773.150%^000000 l ^77777745%^000000\n[Nv 10]: ^7777773.500%^000000 l ^77777750%^000000" },
  "From the Abyss": { id: 5317, label: "Invocação do Abismo", description: "Invocação do Abismo ^777777(From the Abyss)^000000\nNível máximo: ^7777775^000000\nPré-requisito: ^777777Lâmina Mágica 3^000000\nTipo: ^777777Ativa^000000\nRegen. de AP: ^0054FF4 a 20^000000\nDescrição:\n^777777Permite invocar 5 orbes do abismo.\nAo realizar ataques básicos, há chance de\nconsumir 1 orbe para causar dano mágico de\npropriedade Neutro no alvo e oponentes na\nárea de 9x9 células ao redor. Os orbes\nconsumidos são regenerados com o tempo.\nNível de base e FEI aumentam o dano.^000000\nNível l ATQM l Duração\n[Nv 1]: ^777777220%^000000 l ^77777730 segundos^000000 l ^7777773,0 segundos^000000\n[Nv 2]: ^777777290%^000000 l ^77777760 segundos^000000 l ^7777772,5 segundos^000000\n[Nv 3]: ^777777360%^000000 l ^77777790 segundos^000000 l ^7777772,0 segundos^000000\n[Nv 4]: ^777777430%^000000 l ^777777120 segundos^000000 l ^7777771,5 segundos^000000\n[Nv 5]: ^777777500%^000000 l ^777777150 segundos^000000 l ^7777771,0 segundos^000000" },
