  "Grand Cross": { id: 254, label: "Crux Magnum", description: "Crux Magnum ^777777(Grand Cross)^000000\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Fé 10, Crux Divinum 6^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Causa dano híbrido (físico e mágico) de\npropriedade Sagrado ao redor do usuário.\nEm monstros da raça Morto-Vivo e Demônio,\nexiste uma chance de infligir Cegueira.^000000\n^000088Consome 20% de HP do usuário.^000000\nNível l ATQ e ATQM\n[Nv 1]: ^777777140%^000000\n[Nv 2]: ^777777180%^000000\n[Nv 3]: ^777777220%^000000\n[Nv 4]: ^777777260%^000000\n[Nv 5]: ^777777300%^000000\n[Nv 6]: ^777777340%^000000\n[Nv 7]: ^777777380%^000000\n[Nv 8]: ^777777420%^000000\n[Nv 9]: ^777777460%^000000\n[Nv 10]: ^777777500%^000000" },
  "Gravitational Field": { id: 484, label: "Campo Gravitacional", description: "Campo Gravitacional ^777777(Gravitational Field)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Amplificação Mística 10,\nEsmagamento Mágico 1, Pântano dos Mortos 1^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Reduz a gravidade na área de 5x5 células e\ncausa dano mágico de propriedade Neutro.^000000\nNível l ATQM l Ataques\n[Nv 1]: ^777777100%^000000 l ^7777772^000000\n[Nv 2]: ^777777200%^000000 l ^7777774^000000\n[Nv 3]: ^777777300%^000000 l ^7777776^000000\n[Nv 4]: ^777777400%^000000 l ^7777778^000000\n[Nv 5]: ^777777500%^000000 l ^77777710^000000" },
  "Great Echo": { id: 2426, label: "Brado de Odin", description: "Brado de Odin ^777777(Great Echo)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Ruído Estridente 1^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^008080Apenas Chicotes ou Instrumentos.^000000\n^777777Um eco que causa dano físico a distância\nnos alvos próximos da área selecionada.\nO dano é afetado pelo nível de base, nível de\n[Domínio Musical] e é dobrado se houver mais\num artista no grupo.^000000\n^000088Consome 2 Pastilhas Refrescantes.^000000\nNível l Área l ATQ\n[Nv 1]: ^7777775x5 células^000000 l ^777777750%^000000\n[Nv 2]: ^7777777x7 células^000000 l ^7777771.250%^000000\n[Nv 3]: ^7777777x7 células^000000 l ^7777771.750%^000000\n[Nv 4]: ^7777779x9 células^000000 l ^7777772.250%^000000\n[Nv 5]: ^7777779x9 células^000000 l ^7777772.750%^000000" },
