  "Knuckle Arrow": { id: 2336, label: "Pancada Corporal", description: "Pancada Corporal ^777777(Knuckle Arrow)^000000\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Salto Relâmpago 1^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Joga o corpo contra o alvo para causar dano\nfísico a distância e empurrá-lo para trás.\nHá um bônus se o alvo bater na parede e\nmonstros Chefes receberão mais dano.\nO peso do alvo influencia no dano causado.\nNão consome 1 Esfera do nível 6 em diante.^000000\n^000088Consome 1 Esfera Espiritual.^000000\nNível l ATQ l ATQ (Empurrão) l ATQ (Chefe)\n[Nv 1]: ^777777600%^000000 l ^777777150%^000000 l ^777777700%^000000\n[Nv 2]: ^777777700%^000000 l ^777777300% ^000000 l ^777777900%^000000\n[Nv 3]: ^777777800%^000000 l ^777777450%^000000 l ^7777771.100%^000000\n[Nv 4]: ^777777900%^000000 l ^777777600%^000000 l ^7777771.300%^000000\n[Nv 5]: ^7777771.000%^000000 l ^777777750%^000000 l ^7777771.500%^000000\n[Nv 6]: ^7777771.100%^000000 l ^777777900%^000000 l ^7777771.700%^000000\n[Nv 7]: ^7777771.200%^000000 l ^7777771.050% ^000000 l ^7777771.900%^000000\n[Nv 8]: ^7777771.300%^000000 l ^7777771.200%^000000 l ^7777772.100%^000000\n[Nv 9]: ^7777771.400%^000000 l ^7777771.350%^000000 l ^7777772.300%^000000\n[Nv 10]: ^7777771.500%^000000 l ^7777771.500%^000000 l ^7777772.500%^000000" },
  "Knuckle Boost": { id: 2256, label: "Punho Foguete", description: "Punho Foguete ^777777(Boost Knuckle)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Licença de Pilotagem 1^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^008080Apenas com M.E.C.H.A.^000000\n^777777Causa dano físico a distância em um único\nalvo com até 11 células de alcance.\nDES e nv. de base afetam o dano causado.^000000\nNível l ATQ l SP\n[Nv 1]: ^777777340%^000000 l ^7777775^000000\n[Nv 2]: ^777777580%^000000 l ^77777710^000000\n[Nv 3]: ^777777820%^000000 l ^77777715^000000\n[Nv 4]: ^7777771.060%^000000 l ^77777720^000000\n[Nv 5]: ^7777771.300%^000000 l ^77777725^000000" },
  "Kunai Explosion": { id: 3006, label: "Kunai Explosiva", description: "Kunai Explosiva ^777777(Kunai Explosion)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Arremessar Kunai 5^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Joga uma Kunai explosiva no alvo, causando\ndano físico a distância em 5x5 células.\nO nível de base do usuário aumenta o dano.^000000\n^000088Consome 1 Kunai Explosiva.^000000\nNível l Alcance l Conjuração variável\n[Nv 1]: ^7777777 células^000000 l ^7777771,0 segundo^000000\n[Nv 2]: ^7777778 células^000000 l ^7777771,4 segundos^000000\n[Nv 3]: ^7777779 células^000000 l ^7777771,8 segundos^000000\n[Nv 4]: ^77777710 células^000000 l ^7777772,2 segundos^000000\n[Nv 5]: ^77777711 células^000000 l ^7777772,6 segundos^000000" },
