  "Lightning Land": { id: 5370, label: "Tormenta", description: "Tormenta ^777777(Lightning Land)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Estudo Elemental 2^000000\nTipo: ^777777Ofensiva^000000\nRegen. de AP: ^0054FF5^000000\nDescrição:\n^777777Cria uma tempestade elétrica na área de\n9x9 células que dura 3 segundos, causando\ndano mágico de propriedade Vento a cada\n0,3 segundo, com chance de infligir o\nefeito de [Eletrificação] nos oponentes.\nO dano aumenta se Procella for invocada.\nNível de base e FEI influenciam o dano.^000000\nNível l ATQM l ATQM (Procella) l Chance\n[Nv 1]: ^777777400%^000000 l ^777777800%^000000 l ^77777720%^000000\n[Nv 2]: ^777777800%^000000 l ^7777771.600%^000000 l ^77777730%^000000\n[Nv 3]: ^7777771.200%^000000 l ^7777772.400%^000000 l ^77777740%^000000\n[Nv 4]: ^7777771.600%^000000 l ^7777773.200%^000000 l ^77777750%^000000\n[Nv 5]: ^7777772.000%^000000 l ^7777774.000%^000000 l ^77777760%^000000" },
  "Lightning Ride": { id: 2518, label: "Tempestade Espiritual", description: "Tempestade Espiritual ^777777(Lightning Ride)^000000\nNível máximo: ^7777775^000000\nPré-requisitos:\n ^777777Disparo de Esferas Espirituais 3^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Causa dano físico a distância na área.\nHá um bônus no dano se equipar Soqueiras.\nO nível de base afeta o dano causado.^000000\n^000088Consome 2 Esferas Espirituais.^000000\nNível l ATQ l ATQ (Bônus) l Área l Golpes\n[Nv 1]: ^77777740%^000000 l ^77777790%^000000 l ^7777773x3 células^000000 l ^7777771^000000\n[Nv 2]: ^77777780%^000000 l ^777777180%^000000 l ^7777773x3 células^000000 l ^7777772^000000\n[Nv 3]: ^777777120%^000000 l ^777777270%^000000 l ^7777775x5 células^000000 l ^7777773^000000\n[Nv 4]: ^777777160%^000000 l ^777777360%^000000 l ^7777775x5 células^000000 l ^7777774^000000\n[Nv 5]: ^777777200%^000000 l ^777777450%^000000 l ^7777777x7 células^000000 l ^7777775^000000" },
  "Lion Howling": { id: 2517, label: "Rugido do Leão", description: "Rugido do Leão ^777777(Howling of Lion)^000000\nNível máximo: ^7777775^000000\nPré-requisitos:  ^777777Absorção Espiritual 1,\nTempestade Espiritual 3^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Grita para causar dano físico a distância\naos oponentes ao seu redor e cancelando as\nmúsicas e danças de Trovadores e Musas que\nestão ativas no alvo. O dano é afetado\npelo seu nível de base.^000000\n^000088Consome 3 Esferas Espirituais.^000000\nNível l ATQ l Área\n[Nv 1]: ^777777500%^000000 l ^7777775x5 células^000000\n[Nv 2]: ^7777771.000%^000000 l ^7777775x5 células^000000\n[Nv 3]: ^7777771.500%^000000 l ^7777777x7 células^000000\n[Nv 4]: ^7777772.000%^000000 l ^7777775x5 células^000000\n[Nv 5]: ^7777772.500%^000000 l ^7777779x9 células^000000" },
  "Lord of Vermilion": { id: 85, label: "Ira de Thor", description: "Ira de Thor ^777777(Lord of Vermilion)^000000\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Trovão de Júpiter 5,\nTempestade de Raios 1^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Dispara trovões na área de 13x13 células.\nCada trovão ocupa 3x3 células e atinge 10\nvezes um mesmo alvo a cada 1 segundo.\nCausa dano mágico de propriedade Vento e\ntem chance de infligir o status Cegueira.^000000\nNível l ATQM l Chance\n[Nv 1]: ^777777500%^000000 l ^77777715%^000000\n[Nv 2]: ^777777600%^000000 l ^77777720% ^000000\n[Nv 3]: ^777777700%^000000 l ^77777725%^000000\n[Nv 4]: ^777777800%^000000 l ^77777730% ^000000\n[Nv 5]: ^777777900%^000000 l ^77777735% ^000000\n[Nv 6]: ^7777771.000%^000000 l ^77777740%^000000\n[Nv 7]: ^7777771.100%^000000 l ^77777745% ^000000\n[Nv 8]: ^7777771.200%^000000 l ^77777750% ^000000\n[Nv 9]: ^7777771.300%^000000 l ^77777755%^000000\n[Nv 10]: ^7777771.400%^000000 l ^77777760%^000000" },
