  "Lunatic Carrot Beat": { id: 5036, label: "Cometas Lunáticos", description: "Cometas Lunáticos ^777777(Lunatic Carrot Beat)^000000\nNível máximo: ^7777775^000000\nTipo: ^777777Ofensiva^000000 / ^CD3278Fauna^000000\nPré-requisitos: ^777777Ferida de Tarou 3^000000\nDescrição:\n^777777Invoca várias cenouras de Lunático para\ncausar dano físico na área próxima do alvo.\nSe o item Cenoura estiver no inventário,\nadiciona a chance de infligir Atordoamento.\nSe tiver nv. base 100 ou mais, o dano\naumenta de acordo com o nível de base\ne a FOR do usuário.^000000\n^000088Consome 1 Cenoura (Opcional).^000000\nNível l ATQ l Área\n[Nv 1]: ^777777300%^000000 l ^7777773x3 células^000000\n[Nv 2]: ^777777400%^000000 l ^7777773x3 células^000000\n[Nv 3]: ^777777500%^000000 l ^7777775x5 células^000000\n[Nv 4]: ^777777600%^000000 l ^7777775x5 células^000000\n[Nv 5]: ^777777700%^000000 l ^7777777x7 células^000000" },
  "Madness Crusher": { id: 5211, label: "Cólera Esmagadora", description: "Cólera Esmagadora ^777777(Madness Crusher)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Acúmulo de Poder 5,\nCorte e Massacre 10^000000\nTipo: ^777777Ofensiva^000000\nRegen. de AP: ^0054FF2^000000\nDescrição:\n^008080Apenas Lança e Espada de 2 Mãos^000000\n^777777Causa dano físico a distância no alvo e\nem todos os oponentes próximos a ele.\nO dano é influenciado pelo Nível e Peso\nda arma, seu Nível de base e POD.^000000\nNível l ATQ l Área\n[Nv 1]: ^777777600%^000000 l ^7777773x3 células^000000\n[Nv 2]: ^7777771.200%^000000 l ^7777775x5 células^000000\n[Nv 3]: ^7777771.800%^000000 l ^7777775x5 células^000000\n[Nv 4]: ^7777772.400%^000000 l ^7777777x7 células^000000\n[Nv 5]: ^7777773.000%^000000 l ^7777777x7 células^000000" },
  "Magazine for One": { id: 5408, label: "Artilharia Pesada", description: "Artilharia Pesada\nMAX Lv : 5\n^777777Skill requirement : P.F.I 3, Intensive Aim 1^000000\nSkill form : ^993300Active^000000\nType : ^777777Range Physical^000000\nTarget : ^777777Single Target^000000\nRecovery : ^0054FFAP 1^000000\nDetails: ^777777Gatling gun and Revolver exclusive skills.\nFires multiple bullets at one target, inflicting long range physical damage to the target.\nWhen cast with a Gatling gun, it attacks 10 times and consumes 40 equipped bullets.\nWhen cast with a Revolver, it attacks 6 times, critical damage is applied according to the caster's critical probability, and 6 equipped bullets are consumed.\nIn the case of critical damage, half of the total critical damage increase options are applied.\nIf there is an aiming count, the aiming count is consumed and the damage increases according to the number of aiming counts consumed. Damage is additionally increased according to the caster's base level and CON.^000000\n^ffffff_^000000\n[Lv 1] : ^777777Per hit ATK(Gatling) 500+(Aiming count x50)%\nPer hit ATK(Revolver) 500+(Aiming count x50)%^000000\n[Lv 2] : ^777777Per hit ATK(Gatling) 800+(Aiming count x100)%\nPer hit ATK(Revolver) 900+(Aiming count x100)%^000000\n[Lv 3] : ^777777Per hit ATK(Gatling) 1100+(Aiming count x150)%\nPer hit ATK(Revolver)1300+(Aiming count x150)%^000000\n[Lv 4] : ^777777Per hit ATK(Gatling) 1400+(Aiming count x200)%\nPer hit ATK(Revolver)1700+(Aiming count x200)%^000000\n[Lv 5] : ^777777Per hit ATK(Gatling) 1700+(Aiming count x250)%\nPer hit ATK(Revolver)2100+(Aiming count x250)%^000000" },
  "Magnum Break": { id: 7, label: "Impacto Explosivo", description: "Impacto Explosivo ^777777(Magnum Break)^000000\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Golpe Fulminante 5^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Causa dano físico corpo a corpo de\npropriedade Fogo em 5x5 células ao redor.\nAlvos atingidos serão empurrados e nos\npróximos 10 segundos, o dano físico do\nusuário é aumentado em 20%.^000000\nNível l ATQ\n[Nv 1]: ^777777120%^000000\n[Nv 2]: ^777777140%^000000\n[Nv 3]: ^777777160%^000000\n[Nv 4]: ^777777180%^000000\n[Nv 5]: ^777777200%^000000\n[Nv 6]: ^777777220%^000000\n[Nv 7]: ^777777240%^000000\n[Nv 8]: ^777777260%^000000\n[Nv 9]: ^777777280%^000000\n[Nv 10]: ^777777300%^000000" },
