  "Mammonite": { id: 42, label: "Mammonita", description: "Mammonita\nNível máximo: ^77777710^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Causa dano físico corpo a corpo.\nCusta 5 de SP.^000000\n^000088Consome zenys.^000000\nNível l ATQ l Zenys gastos\n[Nv 1]: ^777777150%^000000 l ^777777100 zenys^000000\n[Nv 2]: ^777777200%^000000 l ^777777200 zenys^000000\n[Nv 3]: ^777777250%^000000 l ^777777300 zenys^000000\n[Nv 4]: ^777777300%^000000 l ^777777400 zenys^000000\n[Nv 5]: ^777777350%^000000 l ^777777500 zenys^000000\n[Nv 6]: ^777777400%^000000 l ^777777600 zenys^000000\n[Nv 7]: ^777777450%^000000 l ^777777700 zenys^000000\n[Nv 8]: ^777777500%^000000 l ^777777800 zenys^000000\n[Nv 9]: ^777777550%^000000 l ^777777900 zenys^000000\n[Nv 10]: ^777777600%^000000 l ^7777771.000 zenys^000000" },
  "Mandragora Howling": { id: 2492, label: "Grito da Mandrágora", description: "Grito da Mandrágora ^777777(Mandragora Howling)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Planta Infernal 3^000000\nTipo: ^777777Ativa^000000\nDescrição:\n^777777Concede a chance de reduzir a INT, drenar\no SP e aumentar o tempo de conjuração\nfixa dos oponentes ao redor do usuário.\nA chance será menor conforme a VIT\ne SOR dos adversários.\nNão funciona em monstros.^000000\n^000088Consome 1 Muda de Mandrágora.^000000\nNível l Área l SP drenado l INT\n[Nv 1]: ^77777711x11 células^000000 l ^77777730%^000000 l ^777777-4^000000\n[Nv 2]: ^77777713x13 células^000000 l ^77777735%^000000 l ^777777-8^000000\n[Nv 3]: ^77777713x13 células^000000 l ^77777740%^000000 l ^777777-12^000000\n[Nv 4]: ^77777715x15 células^000000 l ^77777745%^000000 l ^777777-16^000000\n[Nv 5]: ^77777715x15 células^000000 l ^77777750%^000000 l ^777777-20^000000" },
  "Masquerade-Enervation": { id: 2292, label: "Máscara da Fraqueza", description: "Máscara da Fraqueza ^777777(M. Enervation)^000000\nNível máximo: ^7777773^000000\nPré-requisitos: ^777777Borrifar Tinta 1^000000\nTipo: ^777777Ativa^000000\nDescrição:\n^777777Concede a chance de reduzir o ATQ do alvo\ne remover todas as Esferas Espirituais.\nNão funciona contra monstros Chefes.^000000\n^000088Consome 1 Tinta para Pele.\nPrecisa de 1 Pincel de Maquiagem.^000000\nNível l ATQ l Duração\n[Nv 1]: ^777777-30%^000000 l ^77777710 segundos^000000\n[Nv 2]: ^777777-40%^000000 l ^77777715 segundos^000000\n[Nv 3]: ^777777-50%^000000 l ^77777720 segundos^000000" },
