  "Masquerade-Weakness": { id: 2297, label: "Máscara da Vulnerabilidade", description: "Máscara da Vulnerabilidade ^777777(M. Weakness)^000000\nNível máximo: ^7777773^000000\nPré-requisitos: ^777777Máscara da Melancolia 1\nMáscara da Fraqueza 1, Máscara da Tolice 1^000000\nTipo: ^777777Ativa^000000\nDescrição:\n^777777Concede a chance de reduzir o HP máx. do\nalvo e remover o Escudo e a Arma dele.\nNão funciona contra monstros Chefes.^000000\n^000088Consome 1 Tinta para Pele.\nPrecisa de 1 Pincel de Maquiagem.^000000\nNível l HP máx. l Duração\n[Nv 1]: ^777777-10%^000000 l ^77777710 segundos^000000\n[Nv 2]: ^777777-20%^000000 l ^77777715 segundos^000000\n[Nv 3]: ^777777-30%^000000 l ^77777720 segundos^000000" },
  "Mass Spiral": { id: 2553, label: "Espiral Perfurante", description: "Espiral Perfurante ^777777(Mass Spiral)^000000\nNível máximo: ^7777775^000000\nPré-requisitos: ^777777Ferir Alvo 1^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^008080Apenas com Rifles.^000000\n^777777Causa dano físico a distância com chance de\ninfligir Sangramento no alvo selecionado.\nA DEF do alvo aumenta o dano causado.^000000\n^000088Consome 1 Projétil Revestido.^000000\nNível l Chance l ATQ\n[Nv. 1]: ^77777740%^000000 l ^777777200%^000000\n[Nv. 2]: ^77777750%^000000 l ^777777400%^000000\n[Nv. 3]: ^77777760%^000000 l ^777777600%^000000\n[Nv. 4]: ^77777770%^000000 l ^777777800%^000000\n[Nv. 5]: ^77777780%^000000 l ^7777771.000%^000000" },
  "Massive Flame Blaster": { id: 5243, label: "Punho Labareda", description: "Punho Labareda ^777777(Massive Flame Blaster)^000000\nNível máximo: ^77777710^000000\nPré-requisito: ^777777Técnica da Mão Explosiva 3\nOleum Sanctum 3, Caminhos da Fé 5^000000\nTipo: ^777777Ofensiva^000000\nCusto de AP: ^FF0000150^000000\nDescrição:\n^777777Causa dano físico à distância no alvo e\nem oponentes 9x9 células ao redor. Contra\nas raças Bruto e Demônio, causa mais dano.\nNível de base e POD influenciam no dano.\nTem chance do ataque ser crítico.\nA chance é igual ao CRIT do usuário.\nAtiva o estado de [Fervor Espiritual] em\nvocê por 300 segundos.^000000\nFervor Espiritual:\n^777777Permite usar Explosão Espiritual e\nTempestade Espiritual sem consumir\nEsferas Espirituais.^000000\nNível l ATQ l ATQ (Demônio e Bruto)\n[Nv 1]: ^777777800%^000000 l ^7777771.100%^000000\n[Nv 2]: ^7777771.600%^000000 l ^7777772.200%^000000\n[Nv 3]: ^7777772.400%^000000 l ^7777773.300%^000000\n[Nv 4]: ^7777773.200%^000000 l ^7777774.400%^000000\n[Nv 5]: ^7777774.000%^000000 l ^7777775.500%^000000\n[Nv 6]: ^7777774.800%^000000 l ^7777776.600%^000000\n[Nv 7]: ^7777775.600%^000000 l ^7777777.700%^000000\n[Nv 8]: ^7777776.400%^000000 l ^7777778.800%^000000\n[Nv 9]: ^7777777.200%^000000 l ^7777779.900%^000000\n[Nv 10]: ^7777778.000%^000000 l ^77777711.000%^000000" },
  "Metalic Sound": { id: 2413, label: "Ruído Estridente", description: "Ruído Estridente ^777777(Metallic Sound)^000000\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Ressonância 5^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Emite um som metálico e causa dano mágico\nde propriedade Neutro em um alvo único.\nO dano é afetado pelo nível de base, pelo\nnível de [Domínio Musical] e se o oponente\nestiver sofrendo de Sono Profundo.^000000\nNível l ATQM\n[Nv 1]: ^777777120%^000000\n[Nv 2]: ^777777240%^000000\n[Nv 3]: ^777777360%^000000\n[Nv 4]: ^777777480%^000000\n[Nv 5]: ^777777600%^000000\n[Nv 6]: ^777777720%^000000\n[Nv 7]: ^777777840%^000000\n[Nv 8]: ^777777960%^000000\n[Nv 9]: ^7777771.080%^000000\n[Nv 10]: ^7777771.200%^000000" },
  "Meteor Assault": { id: 406, label: "Impacto Meteoro", description: "Impacto Meteoro ^777777(Meteor Assault)^000000\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Perícia com Mão Direita 3\nPerícia com Katar 5, Destruidor de Almas 1\nLâminas Destruidoras 5^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Causa dano físico corpo a corpo na\nárea de 5x5 células ao redor do usuário.\nAlvos atingidos poderão ter [Sangramento],\n[Cegueira] ou [Atordoamento].\nO nível de base influencia no dano causado.^000000\nNível l ATQ\n[Nv 1]: ^777777320%^000000\n[Nv 2]: ^777777440%^000000\n[Nv 3]: ^777777560%^000000\n[Nv 4]: ^777777680%^000000\n[Nv 5]: ^777777800%^000000\n[Nv 6]: ^777777920%^000000\n[Nv 7]: ^7777771.040%^000000\n[Nv 8]: ^7777771.160%^000000\n[Nv 9]: ^7777771.280%^000000\n[Nv 10]: ^7777771.400%^000000" },
  "Meteor Storm": { id: 83, label: "Chuva de Meteoros", description: "Chuva de Meteoros ^777777(Meteor Storm)^000000\nNível máximo: ^77777710^000000\nPré-requisitos: ^777777Supernova 2,\nTempestade de Raios 1^000000\nTipo: ^777777Ofensiva^000000\nDescrição:\n^777777Abre passagem para meteoros caírem\naleatoriamente numa área de 13x13 células.\nCada meteoro ocupa 7x7 células e causa\n125% de dano mágico de propriedade Fogo.\nTem uma chance de infligir Atordoamento.^000000\nNível l Meteoros l Golpes l Chance\n[Nv 1]: ^7777772 Meteoros^000000 l ^7777771^000000 l ^7777773%^000000\n[Nv 2]: ^7777773 Meteoros^000000 l ^7777771^000000 l ^7777776%^000000\n[Nv 3]: ^7777773 Meteoros^000000 l ^7777772^000000 l ^7777779%^000000\n[Nv 4]: ^7777774 Meteoros^000000 l ^7777772^000000 l ^77777712%^000000\n[Nv 5]: ^7777774 Meteoros^000000 l ^7777773^000000 l ^77777715%^000000\n[Nv 6]: ^7777775 Meteoros^000000 l ^7777773^000000 l ^77777718%^000000\n[Nv 7]: ^7777775 Meteoros^000000 l ^7777774^000000 l ^77777721%^000000\n[Nv 8]: ^7777776 Meteoros^000000 l ^7777774^000000 l ^77777724%^000000\n[Nv 9]: ^7777776 Meteoros^000000 l ^7777775^000000 l ^77777727%^000000\n[Nv 10]: ^7777777 Meteoros^000000 l ^7777775^000000 l ^77777730%^000000" },
